// // This module reads the ADC input on the falling edge of the clock and outputs it.
module adc_interface(  
    input wire clk,  
    input wire [15:0] adc_input,  
    output reg [15:0] adc_output  
);  
    always @(posedge clk) begin  
        adc_output <= adc_input;  
    end  
endmodule
